183	PsiMsDaq_RetCode_t PsiMsDaq_GetStrHandle(	PsiMsDaq_IpHandle ipHandle,
184												const uint8_t streamNr,
185												PsiMsDaq_StrHandle* const strHndl_p)
186	{
187		//Pointer Cast
188		PsiMsDaq_Inst_t* inst_p = (PsiMsDaq_Inst_t*) ipHandle;
189		//Checks
190		SAFE_CALL(CheckStrNr(ipHandle, streamNr));
191		//Implementation
192		*strHndl_p = (PsiMsDaq_StrHandle) &inst_p->streams[streamNr];
193		//Done
194		return PsiMsDaq_RetCode_Success;
195	}
