197	void PsiMsDaq_HandleIrq(PsiMsDaq_IpHandle ipHandle)
198	{
199		//Pointer Cast
200		PsiMsDaq_Inst_t* inst_p = (PsiMsDaq_Inst_t*) ipHandle;
201	
202		//Check which stream caused the IRQ and acknowledge it
203		uint32_t strWithIrq;
204		PsiMsDaq_RegRead(ipHandle, PSI_MS_DAQ_REG_IRQVEC, &strWithIrq);
205		PsiMsDaq_RegWrite(ipHandle, PSI_MS_DAQ_REG_IRQVEC, strWithIrq);
206	
207		//Call handler for all streams with new windows pending
208		for (int str = 0; str < inst_p->maxStreams; str++) {
209			//Get stream handle
210			PsiMsDaq_StrInst_t* str_p = &inst_p->streams[str];
211			PsiMsDaq_StrHandle strHandle = (PsiMsDaq_StrHandle) str_p;
212	
213			//Continue if stream has no IRQ pending
214			if (0 == (strWithIrq & (1 << str))){
215				continue;
216			}
217	
218			//IRQ Handling Type: Stream
219			if (NULL != str_p->irqFctStr) {
220				str_p->irqFctStr(strHandle, str_p->irqArg);
221			}
222	
223	
224			//IRQ Handling Type: Window
225			if (NULL != str_p->irqFctWin) {
226	
227				uint8_t lastWin;
228				PsiMsDaq_Str_GetLastWrittenWin(strHandle, &lastWin);
229	
230				//Call user callbacks for new windows
231				int8_t win = str_p->lastProcWin;
232				do {
233					//Check if new data arrived and clear stream IRQ
234					PsiMsDaq_RegWrite(ipHandle, PSI_MS_DAQ_REG_IRQVEC, (1 << str));
235					PsiMsDaq_Str_GetLastWrittenWin(strHandle, &lastWin);
236					//Choose next window
237					win = (win + 1) % str_p->windows;
238					//Stopp if this window was not yet marked as free by the user
239					if (str_p->irqCalledWin & (1 << win)) {
240						break;
241					}
242					str_p->irqCalledWin |= (1 << win);
243					//Call user IRQ
244					PsiMsDaq_WinInfo_t winInfo;
245					winInfo.ipHandle = ipHandle;
246					winInfo.strHandle = strHandle;
247					winInfo.winNr = win;
248					if (str_p->irqFctWin != NULL) {
249						str_p->irqFctWin(winInfo, str_p->irqArg);
250					}
251					//Update State
252					str_p->lastProcWin = win;
253				} while (win != lastWin);
254			}
255		}
256	
257	
258	}
