579	PsiMsDaq_RetCode_t PsiMsDaq_StrWin_GetDataUnwrapped(	PsiMsDaq_WinInfo_t winInfo,
580															const uint32_t preTrigSamples,
581															const uint32_t postTrigSamples,	//including trigger
582															void* const buffer_p,
583															const size_t bufferSize)
584	{
585		//Pointer Cast
586		PsiMsDaq_StrInst_t* str_p = (PsiMsDaq_StrInst_t*) winInfo.strHandle;
587		PsiMsDaq_Inst_t* ip_p = (PsiMsDaq_Inst_t*) winInfo.ipHandle;
588	
589		//Setup
590		const uint32_t samples = preTrigSamples+postTrigSamples;
591		const uint32_t bytes = samples*str_p->widthBytes;
592		uint32_t preTrig;
593		SAFE_CALL(PsiMsDaq_StrWin_GetPreTrigSamples(winInfo, &preTrig));
594	
595		//Checks
596		if (bufferSize < bytes) {
597			return PsiMsDaq_RetCode_BufferTooSmall;
598		}
599		if (postTrigSamples > str_p->postTrig) {
600			return PsiMsDaq_RetCode_MorePostTrigThanConfigured;
601		}
602		if (preTrigSamples > preTrig) {
603			return PsiMsDaq_RetCode_MorePreTrigThanAvailable;
604		}
605	
606		//Calculate window addresses
607		const uint32_t winStart = str_p->bufStart + str_p->winSize*winInfo.winNr;
608		const uint32_t winLast = winStart + str_p->winSize - 1;
609	
610		//Calculate address of last byte and trigger byte (with regard to wrapping)
611		uint32_t lastSplAddr;
612		SAFE_CALL(PsiMsDaq_StrWin_GetLastSplAddr(winInfo, &lastSplAddr));
613		uint32_t trigByteAddr = lastSplAddr - str_p->postTrig*str_p->widthBytes;
614		if (trigByteAddr < winStart) {
615			trigByteAddr += str_p->winSize;
616		}
617		uint32_t lastByteAddr = trigByteAddr + postTrigSamples*str_p->widthBytes + str_p->widthBytes-1;
618		if (lastByteAddr > winLast) {
619			lastByteAddr -= str_p->winSize;
620		}
621	
622	
623		//If all bytes are written without wrap, copy directly
624		const int64_t firstByteLinear = (int64_t)lastByteAddr - bytes + 1;
625		if (firstByteLinear >= winStart) {
626			ip_p->memcpyFct(buffer_p, (void*)(size_t)firstByteLinear, bytes);
627		}
628		//Do unwrapping else
629		else {
630			const uint32_t secondChunkSize = lastByteAddr - winStart + 1;
631			const uint32_t firstChunkSize = bytes-secondChunkSize;
632			const int64_t firstChunkStartAddr = winLast-firstChunkSize+1;
633			ip_p->memcpyFct(buffer_p, (void*)(size_t)firstChunkStartAddr, firstChunkSize);	
634			ip_p->memcpyFct((void*)((uint32_t)buffer_p+firstChunkSize), (void*)(size_t)winStart, secondChunkSize);
635		}
636	
637		//Done
638		return PsiMsDaq_RetCode_Success;
639	}
