790	PsiMsDaq_RetCode_t PsiMsDaq_RegSetBit(	PsiMsDaq_IpHandle ipHandle,
791												const uint32_t addr,
792												const uint32_t mask,
793												const bool value)
794	{
795		//Execute access
796		uint32_t reg;
797		SAFE_CALL(PsiMsDaq_RegRead(ipHandle, addr, &reg));
798		reg &= ~mask;
799		if (value) {
800			reg |= mask;
801		}
802		SAFE_CALL(PsiMsDaq_RegWrite(ipHandle, addr, reg));
803		//Done
804		return PsiMsDaq_RetCode_Success;
805	}
806	
807	PsiMsDaq_RetCode_t PsiMsDaq_RegGetBit(	PsiMsDaq_IpHandle ipHandle,
808											const uint32_t addr,
809											const uint32_t mask,
810											bool* const value_p)
811	{
812		//Execute access
813		uint32_t reg;
814		SAFE_CALL(PsiMsDaq_RegRead(ipHandle, addr, &reg));
815		*value_p = (0 != (reg & mask));
816		//Done
817		return PsiMsDaq_RetCode_Success;
818	}
