19	//*******************************************************************************
20	// Static variables
21	//*******************************************************************************
22	static AxisDataGen_Inst_t str0Gen;
23	static AxisDataGen_Inst_t str1Gen;
24	static AxisDataGen_Inst_t* const str0Hndl = &str0Gen;
25	static AxisDataGen_Inst_t* const str1Hndl = &str1Gen;
26	static PsiMsDaq_IpHandle daqHandle;
27	static PsiMsDaq_StrHandle daqStr0;
28	static PsiMsDaq_StrHandle daqStr1;
29	static XScuGic gicInst;
30	static char buf[20000*4];
31	
32	
33	//*******************************************************************************
34	// Interrupt handling
35	//*******************************************************************************
36	
37	//Xilinx IRQ handler, just call the psi_ms_daq IRQ handler
38	void PsiMsDaqIrqHandler(void* arg)
39	{
40		printf("\nIrq received\n");
41		PsiMsDaq_IpHandle ipHandle = (PsiMsDaq_IpHandle) arg;
42		//Call IP-handling function
43		PsiMsDaq_HandleIrq(ipHandle);
44	}
45	
46	//Stream 0 IRQ
47	void Str0Irq(PsiMsDaq_WinInfo_t winInfo, void* arg)
48	{
49		//Print notification
50		printf("\nRecieved Str0 IRQ: win %d\n", winInfo.winNr);
51		PsiMsDaq_RetCode_t ret;
52	
53		//Make sue we really read from Memory and not from cache
54		Xil_DCacheInvalidateRange(0x40000000, 32*16);
55	
56		//Print timestamp
57		uint64_t timestamp;
58		ret = PsiMsDaq_StrWin_GetTimestamp(winInfo, &timestamp);
59		if (PsiMsDaq_RetCode_Success != ret) printf("PsiMsDaq_StrWin_GetTimestamp() failed: %d\n", ret);
60		printf("> Timestamp %016lx\n", timestamp);
61	
62		//Get data and print it (mark trigger sample with ..=T)
63		ret = PsiMsDaq_StrWin_GetDataUnwrapped(winInfo, 5, 5, buf, sizeof(buf));
64		if (PsiMsDaq_RetCode_Success != ret) printf("PsiMsDaq_StrWin_GetDataUnwrapped() failed: %d\n", ret);
65		uint16_t* data = (uint16_t*)buf;
66		printf("> Values:");
67		for (int i = 0; i < 10; i++) {
68			printf(" %d", data[i]);
69			//Sample 4 is the trigger sample, mark it in the print
70			if (i == 4) {
71				printf("=T");
72			}
73		}
74		printf("\n");
75	
76		//Mark window as free so new data can be recorded
77		ret = PsiMsDaq_StrWin_MarkAsFree(winInfo);
78		if (PsiMsDaq_RetCode_Success != ret) printf("PsiMsDaq_StrWin_MarkAsFree() failed: %d\n", ret);
79		printf("\n");
80	}
81	
82	//Stream 1 IRQ
83	void Str1Irq(PsiMsDaq_WinInfo_t winInfo, void* arg)
84	{
85		//Print notification
86		printf("\nRecieved Str1 IRQ: win %d\n", winInfo.winNr);
87		PsiMsDaq_RetCode_t ret;
88	
89		//Make sue we really read from Memory and not from cache
90		Xil_DCacheInvalidateRange(0x50000000, 32000*16);
91	
92		//Print timestamp
93		uint64_t timestamp;
94		PsiMsDaq_StrWin_GetTimestamp(winInfo, &timestamp);
95		PsiMsDaq_StrWin_GetTimestamp(winInfo, &timestamp);
96		printf("> Timestamp %016lx\n", timestamp);
97	
98		//Get data and print information
99		const uint32_t POST_TRIG_CHECK = 1000;
100		const uint32_t PRE_TRIG_CHECK = 1000;
101		ret = PsiMsDaq_StrWin_GetDataUnwrapped(winInfo, PRE_TRIG_CHECK, POST_TRIG_CHECK, buf, sizeof(buf));
102		if (PsiMsDaq_RetCode_Success != ret) printf("PsiMsDaq_StrWin_GetDataUnwrapped() failed: %d\n", ret);
103		uint32_t* data = (uint32_t*)buf;
104		printf("> Trigger Sample: %d\n", data[PRE_TRIG_CHECK-1]);
105		printf("> First Sample  : %d\n", data[0]);
106		printf("> Check if continuous ... ");
107		uint32_t exp = data[0];
108		bool failed = false;
109		for (int i = 0; i < PRE_TRIG_CHECK+POST_TRIG_CHECK; i++) {
110			if (exp != data[i]) {
111				failed = true;
112				printf("FAILED at %d\n", i);
113				break;
114			}
115			exp = (exp+1) % 100000;	//Wraparound at 100k
116		}
117		if (!failed){
118			printf("OK\n");
119		}
120	
121		//Mark window as free so new data can be recorded
122		ret = PsiMsDaq_StrWin_MarkAsFree(winInfo);
123		if (PsiMsDaq_RetCode_Success != ret) printf("PsiMsDaq_StrWin_MarkAsFree() failed: %d\n", ret);
124		printf("\n");
125	}
126	
127	//*******************************************************************************
128	// Initialization
129	//*******************************************************************************
130	void Init()
131	{
132		//Test data generator stream 0
133		printf("Initialize DataGenerator 0\n");
134		AxisDataGen_Init(str0Hndl, XPAR_STR0_TESTGEN_GEN_0_BASEADDR);
135		AxisDataGen_Disable(str0Hndl);
136		//Wraparound at 10000, generate triggers at X*1000
137		AxisDataGen_ConfigurePattern(str0Hndl, 10000, 10, 1000, 999, true, true);
138		AxisDataGen_Enable(str0Hndl);
139	
140		//Test data generator stream 1
141		printf("Initialize DataGenerator 1\n");
142		AxisDataGen_Init(str1Hndl, XPAR_STR1_TESTGEN_GEN_1_BASEADDR);
143		AxisDataGen_Disable(str1Hndl);
144		//Wraparound at 100000, generate triggers at X*25000+500
145		AxisDataGen_ConfigurePattern(str1Hndl, 100000, 10, 500, 24999, true, true);
146		AxisDataGen_Enable(str1Hndl);
147	
148		//Data Recorder
149		printf("Initialize Data Recorder\n");
150		PsiMsDaq_RetCode_t ret;
151		daqHandle = PsiMsDaq_Init(XPAR_PSI_MS_DAQ_BASEADDR, 2, 16, NULL);
152		ret = PsiMsDaq_GetStrHandle(daqHandle, 0, &daqStr0);
153		if (PsiMsDaq_RetCode_Success != ret) printf("PsiMsDaq_GetStrHandle(0) failed: %d\n", ret);
154		ret = PsiMsDaq_GetStrHandle(daqHandle, 1, &daqStr1);
155		if (PsiMsDaq_RetCode_Success != ret) printf("PsiMsDaq_GetStrHandle(1) failed: %d\n", ret);
156	
157		//Stream 0 Configure
158		printf("Initialize Stream 0\n");
159		PsiMsDaq_StrConfig_t cfg0 = {
160			.postTrigSamples = 5,
161			.recMode = PsiMsDaqn_RecMode_Continuous,
162			.winAsRingbuf = true,
163			.winOverwrite = false,
164			.winCnt = 3,
165			.bufStartAddr = 0x40000000,
166			.winSize = 32, //in bytes
167			.streamWidthBits = 16
168		};
169		ret = PsiMsDaq_Str_Configure(daqStr0, &cfg0);
170		if (PsiMsDaq_RetCode_Success != ret) printf("PsiMsDaq_Str_Configure(0) failed: %d\n", ret);
171		ret = PsiMsDaq_Str_SetIrqCallbackWin(daqStr0, Str0Irq, NULL);
172		if (PsiMsDaq_RetCode_Success != ret) printf("PsiMsDaq_Str_SetIrqCallbackWin(0) failed: %d\n", ret);
173		ret = PsiMsDaq_Str_SetIrqEnable(daqStr0, true);
174		if (PsiMsDaq_RetCode_Success != ret) printf("PsiMsDaq_Str_SetIrqEnable(0) failed: %d\n", ret);
175		ret = PsiMsDaq_Str_SetEnable(daqStr0, true);
176		if (PsiMsDaq_RetCode_Success != ret) printf("PsiMsDaq_Str_SetEnable(0) failed: %d\n", ret);
177	
178		//Stream 1 Configure
179		printf("Initialize Stream 1\n");
180		PsiMsDaq_StrConfig_t cfg1 = {
181			.postTrigSamples = 1000,
182			.recMode = PsiMsDaqn_RecMode_Continuous,
183			.winAsRingbuf = true,
184			.winOverwrite = false,
185			.winCnt = 6,
186			.bufStartAddr = 0x50000000,
187			.winSize = 32000, //in bytes
188			.streamWidthBits = 32
189		};
190		ret = PsiMsDaq_Str_Configure(daqStr1, &cfg1);
191		if (PsiMsDaq_RetCode_Success != ret) printf("PsiMsDaq_Str_Configure(1) failed: %d\n", ret);
192		ret = PsiMsDaq_Str_SetIrqCallbackWin(daqStr1, Str1Irq, NULL);
193		if (PsiMsDaq_RetCode_Success != ret) printf("PsiMsDaq_Str_SetIrqCallbackWin(1) failed: %d\n", ret);
194		ret = PsiMsDaq_Str_SetIrqEnable(daqStr1, true);
195		if (PsiMsDaq_RetCode_Success != ret) printf("PsiMsDaq_Str_SetIrqEnable(1) failed: %d\n", ret);
196		ret = PsiMsDaq_Str_SetEnable(daqStr1, true);
197		if (PsiMsDaq_RetCode_Success != ret) printf("PsiMsDaq_Str_SetEnable(1) failed: %d\n", ret);
198	
199		//Interrupt Controller (last, since psi_ms_daq is used in IRQ handler)
200		printf("Interrupt Controller\n");
201		XScuGic_Config *IntcConfig;
202		IntcConfig = XScuGic_LookupConfig(XPAR_SCUGIC_SINGLE_DEVICE_ID);
203		XScuGic_CfgInitialize(&gicInst, IntcConfig, IntcConfig->CpuBaseAddress);
204		XScuGic_Disable(&gicInst, XPAR_FABRIC_PSI_MS_DAQ_IRQ_INTR);
205		Xil_ExceptionInit();
206		Xil_ExceptionRegisterHandler(	XIL_EXCEPTION_ID_INT,
207										(Xil_ExceptionHandler) XScuGic_InterruptHandler,
208										&gicInst);
209		XScuGic_SetPriorityTriggerType(&gicInst, XPAR_FABRIC_PSI_MS_DAQ_IRQ_INTR, 0xA0, 0x1);	//0x1 = level sensitive IRQ, 0xA0 is default priority
